Geographic Distribution
## ============================================================
## Map of school locations
## Requires: sf package for spatial data
## ============================================================

if ("latitude" %in% names(schools) && "longitude" %in% names(schools)) {

  schools_geo &lt;- schools |&gt;
    filter(!is.na(latitude), !is.na(longitude)) |&gt;
    mutate(
      lat = as.numeric(latitude),
      lon = as.numeric(longitude)
    ) |&gt;
    filter(between(lat, 40.4, 41.0), between(lon, -74.3, -73.7))

  ggplot(schools_geo, aes(x = lon, y = lat, color = boro)) +
    geom_point(alpha = 0.5, size = 1) +
    scale_color_viridis_d(name = "Borough") +
    labs(
      title = "Geographic Distribution of NYC Schools",
      x = "Longitude",
      y = "Latitude"
    ) +
    theme_minimal() +
    coord_fixed(ratio = 1.2)

} else {
  cat("Geographic coordinates not available in this dataset\n")
}

Space Utilization by District
## ============================================================
## Analyze building space utilization
## ============================================================

if (exists("building_space") && nrow(building_space) &gt; 0) {

  utilization_summary &lt;- building_space |&gt;
    group_by(district) |&gt;
    summarise(
      n_buildings = n_distinct(building_id),
      total_capacity = sum(as.numeric(bldg_capacity), na.rm = TRUE),
      total_enrollment = sum(as.numeric(bldg_enrollment), na.rm = TRUE),
      .groups = "drop"
    ) |&gt;
    mutate(
      utilization_rate = total_enrollment / total_capacity * 100
    ) |&gt;
    arrange(desc(utilization_rate))

  cat("Top 10 Districts by Utilization Rate:\n")
  print(head(utilization_summary, 10))

} else {
  cat("Building space data not available\n")
}

Total Enrollment Trends
## ============================================================
## Enrollment trends over time
## ============================================================

if ("year" %in% names(enrollment) || "school_year" %in% names(enrollment)) {

  year_col &lt;- if ("year" %in% names(enrollment)) "year" else "school_year"

  enrollment_trend &lt;- enrollment |&gt;
    group_by(year = .data[[year_col]]) |&gt;
    summarise(
      total_enrollment = sum(as.numeric(total_enrollment), na.rm = TRUE),
      .groups = "drop"
    ) |&gt;
    arrange(year)

  ggplot(enrollment_trend, aes(x = year, y = total_enrollment, group = 1)) +
    geom_line(color = "steelblue", linewidth = 1.2) +
    geom_point(color = "steelblue", size = 3) +
    scale_y_continuous(labels = scales::comma) +
    labs(
      title = "NYC Public School Enrollment Over Time",
      subtitle = "Source: NYC DOE Open Data",
      x = "School Year",
      y = "Total Enrollment"
    ) +
    theme_minimal(base_size = 14) +
    theme(
      axis.text.x = element_text(angle = 45, hjust = 1),
      plot.title = element_text(face = "bold")
    )

} else {
  cat("Year column not found in enrollment data\n")
}

Enrollment by Grade Level
## ============================================================
## Enrollment distribution by grade level
## ============================================================

# Look for grade-related columns
grade_cols &lt;- names(enrollment)[grep("grade|pk|k_|_k$", names(enrollment), ignore.case = TRUE)]

if (length(grade_cols) &gt; 0) {
  cat("Grade-related columns found:\n")
  print(grade_cols)

  # Pivot to long format for visualization
  enrollment_by_grade &lt;- enrollment |&gt;
    select(any_of(c("dbn", "school_name", grade_cols))) |&gt;
    pivot_longer(
      cols = any_of(grade_cols),
      names_to = "grade",
      values_to = "count"
    ) |&gt;
    group_by(grade) |&gt;
    summarise(total = sum(as.numeric(count), na.rm = TRUE), .groups = "drop") |&gt;
    filter(total &gt; 0) |&gt;
    mutate(grade = fct_reorder(grade, total))

  ggplot(enrollment_by_grade, aes(x = total, y = grade)) +
    geom_col(fill = "darkorange", alpha = 0.8) +
    scale_x_continuous(labels = scales::comma) +
    labs(
      title = "Total Enrollment by Grade Level",
      x = "Total Students",
      y = "Grade"
    ) +
    theme_minimal(base_size = 12)

} else {
  cat("No grade-level columns found\n")
}

Demographics by Borough
## ============================================================
## Demographic breakdown by borough
## ============================================================

if ("borough" %in% names(demographics) || "boro" %in% names(demographics)) {

  boro_col &lt;- if ("borough" %in% names(demographics)) "borough" else "boro"

  demo_by_boro &lt;- demographics |&gt;
    group_by(borough = .data[[boro_col]]) |&gt;
    summarise(
      total_students = sum(as.numeric(total_enrollment), na.rm = TRUE),
      n_schools = n(),
      .groups = "drop"
    ) |&gt;
    arrange(desc(total_students))

  cat("Student Distribution by Borough:\n\n")
  print(demo_by_boro)

} else {
  cat("Borough column not found\n")
}

Attendance by School Type
## ============================================================
## Compare attendance across school types
## ============================================================

if (exists("attendance") && "school_type" %in% names(attendance)) {

  attendance_by_type &lt;- attendance |&gt;
    group_by(school_type) |&gt;
    summarise(
      n_schools = n(),
      avg_attendance = mean(as.numeric(attendance_rate), na.rm = TRUE),
      avg_chronic_absent = mean(as.numeric(chronic_absenteeism_rate), na.rm = TRUE),
      .groups = "drop"
    ) |&gt;
    arrange(desc(avg_attendance))

  cat("Attendance Metrics by School Type:\n\n")
  print(attendance_by_type)

}

Math Proficiency Trends
## ============================================================
## Math proficiency levels over time
## Level 3+ = proficient
## ============================================================

if (exists("math_results") && nrow(math_results) &gt; 0) {

  # Look for year and proficiency columns
  year_col &lt;- intersect(c("year", "school_year", "test_year"), names(math_results))[1]

  if (!is.na(year_col)) {

    # Calculate proficiency rate (Level 3 + Level 4)
    math_proficiency &lt;- math_results |&gt;
      filter(!is.na(.data[[year_col]])) |&gt;
      group_by(year = .data[[year_col]]) |&gt;
      summarise(
        total_tested = sum(as.numeric(number_tested), na.rm = TRUE),
        level_3_4 = sum(as.numeric(level_3_4_count), na.rm = TRUE),
        .groups = "drop"
      ) |&gt;
      mutate(proficiency_rate = level_3_4 / total_tested * 100) |&gt;
      arrange(year)

    ggplot(math_proficiency, aes(x = year, y = proficiency_rate, group = 1)) +
      geom_line(color = "#2E86AB", linewidth = 1.2) +
      geom_point(color = "#2E86AB", size = 3) +
      geom_hline(yintercept = 50, linetype = "dashed", color = "gray50") +
      scale_y_continuous(limits = c(0, 100)) +
      labs(
        title = "NYC Math Proficiency Rate (Grades 3-8)",
        subtitle = "Percentage meeting standards (Level 3+)",
        x = "Year",
        y = "Proficiency Rate (%)"
      ) +
      theme_minimal(base_size = 14) +
      theme(
        axis.text.x = element_text(angle = 45, hjust = 1),
        plot.title = element_text(face = "bold")
      )

  }

} else {
  cat("Math results not available\n")
}

Math vs ELA Comparison
## ============================================================
## Compare Math and ELA proficiency by year
## ============================================================

if (exists("math_results") && exists("ela_results")) {

  # Process both datasets similarly
  process_test_data &lt;- function(df, subject) {
    year_col &lt;- intersect(c("year", "school_year", "test_year"), names(df))[1]
    if (is.na(year_col)) return(NULL)

    df |&gt;
      group_by(year = .data[[year_col]]) |&gt;
      summarise(
        proficiency_rate = sum(as.numeric(level_3_4_count), na.rm = TRUE) /
                          sum(as.numeric(number_tested), na.rm = TRUE) * 100,
        .groups = "drop"
      ) |&gt;
      mutate(subject = subject)
  }

  math_summary &lt;- process_test_data(math_results, "Math")
  ela_summary &lt;- process_test_data(ela_results, "ELA")

  if (!is.null(math_summary) && !is.null(ela_summary)) {
    combined &lt;- bind_rows(math_summary, ela_summary)

    ggplot(combined, aes(x = year, y = proficiency_rate, color = subject, group = subject)) +
      geom_line(linewidth = 1.2) +
      geom_point(size = 3) +
      scale_color_manual(values = c("Math" = "#2E86AB", "ELA" = "#A23B72")) +
      labs(
        title = "Math vs ELA Proficiency Rates",
        subtitle = "NYC Grades 3-8 State Assessments",
        x = "Year",
        y = "Proficiency Rate (%)",
        color = "Subject"
      ) +
      theme_minimal(base_size = 14) +
      theme(
        axis.text.x = element_text(angle = 45, hjust = 1),
        legend.position = "top"
      )
  }

}

Graduation Rate Trends
## ============================================================
## High school graduation rate trends
## ============================================================

if (exists("graduation") && nrow(graduation) &gt; 0) {

  grad_year_col &lt;- intersect(c("cohort_year", "cohort", "year"), names(graduation))[1]
  grad_rate_col &lt;- intersect(c("total_grads_pct", "graduation_rate", "grad_rate"), names(graduation))[1]

  if (!is.na(grad_year_col) && !is.na(grad_rate_col)) {

    grad_trend &lt;- graduation |&gt;
      group_by(year = .data[[grad_year_col]]) |&gt;
      summarise(
        avg_grad_rate = mean(as.numeric(.data[[grad_rate_col]]), na.rm = TRUE),
        .groups = "drop"
      ) |&gt;
      filter(!is.na(year), !is.na(avg_grad_rate)) |&gt;
      arrange(year)

    ggplot(grad_trend, aes(x = year, y = avg_grad_rate, group = 1)) +
      geom_line(color = "forestgreen", linewidth = 1.2) +
      geom_point(color = "forestgreen", size = 3) +
      geom_hline(yintercept = 80, linetype = "dashed", color = "gray50") +
      annotate("text", x = min(grad_trend$year), y = 82, 
               label = "80% Goal", hjust = 0, color = "gray50") +
      scale_y_continuous(limits = c(50, 100)) +
      labs(
        title = "NYC High School Graduation Rate",
        subtitle = "4-Year Cohort Graduation Rate",
        x = "Cohort Year",
        y = "Graduation Rate (%)"
      ) +
      theme_minimal(base_size = 14) +
      theme(axis.text.x = element_text(angle = 45, hjust = 1))

  }

} else {
  cat("Graduation data not available\n")
}

Graduation by Demographics
## ============================================================
## Graduation rates by demographic group
## ============================================================

if (exists("graduation")) {

  # Check for demographic columns
  demo_cols &lt;- c("asian", "black", "hispanic", "white", "male", "female",
                 "ell", "swd", "poverty")
  available_demo &lt;- intersect(demo_cols, names(graduation))

  if (length(available_demo) &gt; 0) {
    cat("Graduation Rate by Demographics:\n\n")

    for (col in available_demo) {
      avg_rate &lt;- mean(as.numeric(graduation[[col]]), na.rm = TRUE)
      if (!is.na(avg_rate)) {
        cat(sprintf("  %s: %.1f%%\n", str_to_title(col), avg_rate))
      }
    }
  }

}

Regents Pass Rates by Subject
## ============================================================
## Regents exam pass rates by subject
## ============================================================

if (exists("regents") && nrow(regents) &gt; 0) {

  if ("regents_exam" %in% names(regents) || "subject" %in% names(regents)) {

    subject_col &lt;- if ("regents_exam" %in% names(regents)) "regents_exam" else "subject"

    regents_summary &lt;- regents |&gt;
      group_by(subject = .data[[subject_col]]) |&gt;
      summarise(
        total_tested = sum(as.numeric(total_tested), na.rm = TRUE),
        total_passed = sum(as.numeric(total_passed_65), na.rm = TRUE),
        .groups = "drop"
      ) |&gt;
      mutate(
        pass_rate = total_passed / total_tested * 100,
        subject = fct_reorder(subject, pass_rate)
      ) |&gt;
      filter(!is.na(subject), total_tested &gt; 1000)

    ggplot(regents_summary, aes(x = pass_rate, y = subject)) +
      geom_col(fill = "slateblue", alpha = 0.8) +
      geom_vline(xintercept = 65, linetype = "dashed", color = "gray50") +
      labs(
        title = "Regents Exam Pass Rates by Subject",
        subtitle = "Passing score = 65+",
        x = "Pass Rate (%)",
        y = NULL
      ) +
      theme_minimal(base_size = 12)

  }

} else {
  cat("Regents data not available\n")
}
